const ICON_DEFAULT="content_copy",ICON_SUCCESS="check",RESET_MS=1200;function getCopyText(e){if(e.dataset.copyTarget)return document.querySelector(e.dataset.copyTarget)?.textContent?.trim()||"";const t=e.closest("[data-copy]")||e.parentElement?.querySelector("[data-copy]");return t?t.getAttribute("href")||t.textContent.trim():""}function fallbackCopy(e){const t=document.createElement("textarea");t.value=e,t.style.position="fixed",t.style.opacity="0",t.style.pointerEvents="none",document.body.appendChild(t),t.select();const o=document.execCommand("copy");return t.remove(),o}document.addEventListener("click",async e=>{const t=e.target.closest(".rd-js-copy");if(!t||t.dataset.copyBusy)return;const o=getCopyText(t);if(!o)return;t.dataset.copyBusy="1";const c=()=>{t.dataset.icon=ICON_SUCCESS,clearTimeout(t._copyTimer),t._copyTimer=setTimeout(()=>{t.dataset.icon=ICON_DEFAULT,delete t.dataset.copyBusy},1200)};try{await navigator.clipboard.writeText(o),c()}catch{fallbackCopy(o)?c():delete t.dataset.copyBusy}});
